package ccxt

type Kucoineu struct {
	*KucoineuCore
	Core          *KucoineuCore
	exchangeTyped *Kucoin
}

func NewKucoineu(userConfig map[string]any) *Kucoineu {
	p := NewKucoineuCore()
	p.Init(userConfig)
	return &Kucoineu{
		KucoineuCore:  p,
		Core:          p,
		exchangeTyped: NewKucoinFromCore(&(p.KucoinCore)),
	}
}
func NewKucoineuFromCore(core *KucoinCore) *Kucoin {
	return &Kucoin{
		KucoinCore:    core,
		Core:          core,
		exchangeTyped: NewExchangeTyped(&core.Exchange),
	}
}

